from Crypto.Util.number import getPrime, isPrime, bytes_to_long
import random

CR7 = 143 # n golos do CR7 por Portugal
PnQ_Size = CR7 * 2
E = 65537
BIT_SIZE_PNQ = 948 # size needed to generate primes with 286 (PnQ_Size) digits each

# n = 
# e = 65537
# c = 

def ndigits(x):
    return len(str(x))

while True:
    p = getPrime(BIT_SIZE_PNQ)
    q = (int(str(p)[CR7:] + str(p)[:CR7]))
    
    if len(str(q)) != PnQ_Size:
        continue

    if not isPrime(q):
        continue
    
    print("p =", p)
    print("q =", q)

    n = p * q
    print("Found valid p, q candidates let's check n lenght")

    if ndigits(n) != 2 * PnQ_Size: # para ajudar os menos safados
        print("F")
        continue
    print("Yessir")
    break
    
msg = b"upCTF{...}"
m = bytes_to_long(msg)
c = pow(m, E, n)

print("n =", n)
print("e =", E)
print("c =", c)
print("p =", p)
print("q =", q)
    

